def generate_signals(df, params):
    import pandas as pd
    import numpy as np

    threshold = params['threshold']
    hold_days = params['hold_days']

    # Compute 5-day return
    df['ret_5'] = df['close'].pct_change(periods=5)

    signals = pd.Series(0, index=df.index)
    position = 0
    days_in_position = 0

    for i in range(len(df)):
        if position != 0:
            days_in_position += 1
            if days_in_position >= hold_days:
                signals.iloc[i] = 0  # exit
                position = 0
                days_in_position = 0
            else:
                signals.iloc[i] = position
        else:
            ret = df['ret_5'].iloc[i]
            if pd.notna(ret):
                if ret > threshold:
                    position = -1  # short
                    days_in_position = 0
                    signals.iloc[i] = -1
                elif ret < -threshold:
                    position = 1   # long
                    days_in_position = 0
                    signals.iloc[i] = 1
                else:
                    signals.iloc[i] = 0
            else:
                signals.iloc[i] = 0
    return signals
